export default class WrappingStack{constructor(t=256){let n=0;const o=[];for(let n=0;n<t;++n)o.push(0);const r=function(r){o[n++]=r,n%=t},u=function(){return n=0===n?t-1:n-1,o[n]},c=function(r){let u=n-Math.floor(r)-1;for(;u<0;)u+=t;return o[u%t]},f=function(r,u){let c=n-Math.floor(r);for(;c<0;)c+=t;o[c%t]=u},e=function(){return n};return{pop:u,push:r,pick:c,put:f,sp:e}}}